import Foundation

/// A menu-item template: the minimal human description we synthesize a full,
/// scored `MenuItem` from. Deliberately just name + description + category +
/// price, so items are generated by the reusable estimator, not hardcoded.
struct DishTemplate {
    var name: String
    var description: String
    var category: MenuCategory
    var price: Double
    /// Chains publish official nutrition; when true we freeze the estimate as
    /// "official" so the app can demonstrate the official-vs-estimated split.
    var official: Bool = false
}

