    private static func make(_ id: String, _ name: String, _ cuisines: [String], _ address: String,
                             _ city: String, _ country: String, _ lat: Double, _ lon: Double,
                             _ price: PriceLevel, _ currency: String, official: Bool, avg: Double?,
                             diet: [DietaryTag]) -> Restaurant {
        Restaurant(id: "sample:" + id, name: name, cuisines: cuisines, address: address, city: city,
                   country: country, location: GeoPoint(latitude: lat, longitude: lon),
                   priceLevel: price, hours: .everyDay(open: 8 * 60, close: 22 * 60),
                   phone: nil, website: nil, currencyCode: currency,
                   hasOfficialNutrition: official, averageMenuHealthScore: avg,
                   providerName: "Locked In Sample", dietaryTags: diet, photoAssetName: nil)
    }

