    ]

    // MARK: Menu synthesis

    /// Build the full menu for a restaurant. Returns an empty array for places
    /// that publish no readable menu.
    static func menu(for restaurant: Restaurant) -> [MenuItem] {
        guard let tag = cuisineTagByID[restaurant.id] else { return [] }
        let templates = templates(forCuisine: tag, official: restaurant.hasOfficialNutrition)
        return templates.map { makeItem(restaurant: restaurant, template: $0) }
    }

    static func makeItem(restaurant: Restaurant, template: DishTemplate) -> MenuItem {
        let itemID = restaurant.id + ":" + slug(template.name)
        let est = MenuNutritionEstimator.estimate(name: template.name, description: template.description)

        // Deterministic component ids so modifications and saved snapshots stay
        // internally consistent across rebuilds.
        var components = est.components
        for i in components.indices {
            components[i].id = "\(itemID)#\(i)"
        }
        let mods = MenuModificationFactory.standard(for: components)

        var item = MenuItem(
            id: itemID,
            restaurantID: restaurant.id,
            name: template.name,
            itemDescription: template.description,
            category: template.category,
            price: template.price,
            currencyCode: restaurant.currencyCode,
            components: components,
            modifications: mods,
            dietaryTags: est.dietaryTags,
            ingredientHints: est.uncertainTerms,
            defaultOilLevel: est.defaultOilLevel,
            sourceKind: est.sourceKind,
            baseConfidence: est.confidence)

        if template.official {
            // Freeze the estimate as published official nutrition. From here on the
            // resolver treats these numbers as authoritative and never re-estimates
            // oil on top of them.
            let resolved = MenuItemResolver.resolve(item: item)
            item.officialNutrition = resolved.perUnit
            item.sourceKind = .official
            item.baseConfidence = .high
        }
        return item
    }

    static func slug(_ s: String) -> String {
        s.lowercased().map { $0.isLetter || $0.isNumber ? $0 : "-" }.reduce(into: "") { acc, ch in
            if ch == "-" && (acc.isEmpty || acc.hasSuffix("-")) { return }
            acc.append(ch)
        }
    }
